            int voreinstellungOberflNrId = 1;
            List[EnComboBoxWerte] werteOberfl = new List[EnComboBoxWerte]();
            DbCombobox dbCb = new DbCombobox();
            if (!dbCb.readWerte("Oberflaeche", werteOberfl))
                return;

            MxLib.Dialog.ComboBoxExt comboBox = new MxLib.Dialog.ComboBoxExt();
            comboBox.load(werteOberfl, voreinstellungOberflNrId, false);
